mapper.select:
SELECT a.id,a.create_time,a.cycle,CONCAT(e.text,"_",a.name) as name,a.product_path,a.region_id,a.satellite,a.issue,a.mosaic_file,a.mark,a.sensor,a.resolution,b.fullname FROM ( SELECT id,create_time,cycle,name,map_url,product_path,region_id,satellite,issue,mosaic_file,model_identify as mark,sensor,resolution,product_id FROM htht_cluster_schedule_product_info WHERE is_release = 1 AND product_id in
#{productId}
AND cycle in
#{cycle}
AND satellite in
#{dataSource}
AND region_id in
#{region}
AND mark in
#{n}
AND issue > #{begin}
AND issue <= #{end}
) a LEFT JOIN htht_region_info b ON a.region_id = b.regionid LEFT JOIN htht_cluster_schedule_product c on a.product_id = c.id LEFT JOIN htht_cluster_schedule_data_category d on c.tree_id = d.id LEFT JOIN htht_cluster_schedule_data_category e on e.id = d.parent_id order by regionlevel,regionid asc,issue desc

SELECT DISTINCT cycle FROM `htht_cluster_schedule_product_info` WHERE 1=1
and product_id in
#{productId}

SELECT DISTINCT satellite FROM `htht_cluster_schedule_product_info` WHERE 1=1
and product_id in
#{productId}

select fullname
from htht_region_info
where regionid = #{regionId}

SELECT id FROM htht_cluster_schedule_product WHERE 1=1
and tree_id in
#{productId}
